<?php require __DIR__ . '/vendor/autoload.php'; $app = require_once __DIR__ . '/bootstrap/app.php'; $app->make(Illuminate\Contracts\Console\Kernel::class)->bootstrap(); use App\Models\User; use App\Models\PayrollPeriod; use App\Services\DtrService; $p = PayrollPeriod::find(3); if(!$p) { die('Period 3 not found'); } $svc = new DtrService(); $user = User::where('payroll_group_id', $p->payroll_group_id)->where('is_active', true)->first(); if(!$user) { die('No active user found in group'); } echo 'Testing single user: ' . $user->name . PHP_EOL; $d = \Carbon\Carbon::parse($p->start_date);  try { $dtr = $svc->generateDtrForEmployee($user, $d, $p->id); if($dtr) { echo 'DTR CREATED! ID: ' . $dtr->id . PHP_EOL; } else { echo 'DTR NOT CREATED (LOCKED OR NULL)' . PHP_EOL; } } catch (\Exception $e) { echo 'ERROR: ' . $e->getMessage() . PHP_EOL; echo 'FILE: ' . $e->getFile() . ':' . $e->getLine() . PHP_EOL; }